class Solution {
    public List<String> removeSubfolders(String[] folder) {
        Set<String> seen = new HashSet<>();
        List<String> result = new ArrayList<>();
        for (String path : folder) {
            if (!seen.contains(path.substring(0, path.lastIndexOf('/')))) {
                seen.add(path);
                result.add(path);
            }
        }
        return result;
    }
}
